/**
 * App Settings - Centralized configuration
 */

const apiUrl = import.meta.env.VITE_API_URL as string | undefined;

export const appSettings = {
  /** API base URL */
  apiUrl: apiUrl || 'http://localhost:5010/web-bff/api/v1',

  appUrl: import.meta.env.VITE_PAGE_URL as string || 'http://localhost:9001',
  /** App name */
  appName: (import.meta.env.VITE_APP_NAME as string) || 'Linm Admin',

  /** Enable SignalR real-time hub */
  enableSignalR: import.meta.env.VITE_ENABLE_SIGNALR === 'true',

  /**
   * Push notification provider: 'fcm' | 'vapid' | 'none'.
   * 'none'  — foreground-only via SignalR (default, safe fallback)
   * 'fcm'   — Firebase Cloud Messaging (tab closed = still notified)
   * 'vapid' — self-hosted VAPID (tab closed = still notified, no Firebase)
   */
  pushProvider: (import.meta.env.VITE_PUSH_PROVIDER as 'fcm' | 'vapid' | 'none') || 'none',

  /** Enable analytics */
  enableAnalytics: import.meta.env.VITE_ENABLE_ANALYTICS === 'true',

  /** Is production environment */
  isProduction: import.meta.env.PROD,

  /** Is development environment */
  isDev: import.meta.env.DEV,

  /**
   * Build information — injected by CI/CD at build time.
   * In local dev these will show placeholder values.
   */
  build: {
    /** Semantic version from package.json, auto-bumped on each merge to main. e.g. "1.0.42" */
    version:  (import.meta.env.VITE_APP_VERSION  as string) || '0.0.0-dev',
    /** GitHub Actions run number — monotonically increasing. e.g. "137" */
    number:   (import.meta.env.VITE_BUILD_NUMBER as string) || 'local',
    /** Short git commit SHA. e.g. "a1b2c3d" */
    sha:      (import.meta.env.VITE_BUILD_SHA    as string) || 'dev',
    /** ISO 8601 build timestamp. e.g. "2026-04-12T08:00:00Z" */
    date:     (import.meta.env.VITE_BUILD_DATE   as string) || new Date().toISOString(),
  },
} as const;

// Dev logging
if (import.meta.env.DEV) {
  console.log('⚙️ App Settings:', {
    apiUrl: appSettings.apiUrl,
    environment: appSettings.isProduction ? 'Production' : 'Development',
    build: appSettings.build,
  });
}
